import cn from 'clsx';
import React from 'react';

function Text(props) {
  var value = props.value,
      className = props.className,
      style = props.style;
  return React.createElement("span", {
    className: cn('yozora-text', className),
    style: style
  }, value);
}

Text.displayName = 'YozoraText';
export default Text;
export { Text };