import React from 'react'

export type MagicPanelActivated = 'navigation' | 'search' | 'about-me' | null

export interface BlogContextData {
  /**
   * Keyword in the searching panel.
   */
  keyword: string
  /**
   * Whether to display the magic-panel.
   */
  magicPanelVisible: boolean
  /**
   * Which magic-panel should be displayed.
   */
  magicPanelActivated: MagicPanelActivated
  /**
   * Update keyword.
   * @param keyword
   */
  setKeyword(keyword: string | ((currentKeyword: string) => string)): void
  /**
   * Update magicPanelVisible.
   * @param visible
   */
  setMagicPanelVisible(
    visible: boolean | ((currentVisible: boolean) => void),
  ): void
  /**
   * Update magicPanelActivated.
   * @param panel
   */
  setMagicPanelActivated(
    activated:
      | MagicPanelActivated
      | ((currentActivated: MagicPanelActivated) => MagicPanelActivated),
  ): void
}

export const initialBlogContextData: BlogContextData = {
  keyword: '',
  magicPanelVisible: false,
  magicPanelActivated: null,
  setKeyword: () => {},
  setMagicPanelVisible: () => {},
  setMagicPanelActivated: () => {},
}

export const BlogContext: React.Context<BlogContextData> =
  React.createContext<BlogContextData>(initialBlogContextData)

export default BlogContext
