import type { APlayerOptions } from 'aplayer'
import 'aplayer/dist/APlayer.min.css'
import cn from 'clsx'
import React, { useEffect, useRef } from 'react'
import classes from './style.module.styl'

export interface ReactAPlayerProps {
  /**
   * Options pass to APlayer.
   */
  options: APlayerOptions
  /**
   * CSS className.
   */
  className?: string
}

export function ReactAPlayer(props: ReactAPlayerProps): React.ReactElement {
  const { options, className } = props
  const containerRef = useRef<HTMLDivElement>(null)

  useEffect(() => {
    if (containerRef.current == null) return
    const target: HTMLDivElement = containerRef.current

    // Dynamic import for ssr.
    void (async function (): Promise<void> {
      const { default: APlayer } = await import('aplayer')
      const aplayer = new APlayer({
        autoplay: false,
        listFolded: true,
        lrcType: 3,
        preload: 'metadata',
        theme: '#F57F17',
        ...options,
        container: target,
      })
    })()
  }, [options])

  return (
    <div ref={containerRef} className={cn(classes.reactAplayer, className)} />
  )
}
